def recursive_split(text, max_chars, separators):
    if len(text) <= max_chars:
        return [text]
    for i, sep in enumerate(separators):
        if sep == "":
            return [text[j:j + max_chars] for j in range(0, len(text), max_chars)]
        if sep in text:
            parts = text.split(sep)
            chunks = []
            current = ""
            for part in parts:
                candidate = current + (sep if current else "") + part
                if len(candidate) <= max_chars:
                    current = candidate
                else:
                    if current:
                        chunks.append(current)
                    current = part
            if current:
                chunks.append(current)
            result = []
            next_seps = separators[i + 1:]
            for chunk in chunks:
                if len(chunk) > max_chars:
                    result.extend(recursive_split(chunk, max_chars, next_seps))
                else:
                    result.append(chunk)
            return result
    return [text]

def chunk_document(text, max_chars, overlap, separators):
    raw_chunks = recursive_split(text, max_chars, separators)
    if overlap <= 0 or len(raw_chunks) <= 1:
        return raw_chunks
    result = [raw_chunks[0]]
    for prev, current in zip(raw_chunks, raw_chunks[1:]):
        carry = prev[-overlap:]
        result.append(carry + current)
    return result

